import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';

/**
 * 🛡️ CORE_ESTAVEL - MOTOR DE ESTRATÉGIAS (SYSTEM HEART)
 * --------------------------------------------------------------------------
 * Atualização Passo 1: Fidelidade Absoluta.
 * A descrição original é preservada no campo 'description'.
 * A limpeza para conciliação é movida para 'cleanedDescription'.
 */

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[];
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',

    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fingerprint = Fingerprinter.generate(content);
        if (!fingerprint) return false;

        return models.some(m => 
            m.fingerprint.delimiter === fingerprint.delimiter &&
            m.fingerprint.columnCount === fingerprint.columnCount
        );
    },

    parse: (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];
        const fingerprint = Fingerprinter.generate(content);
        if (!fingerprint) return [];

        const matchingModel = models.find(m => 
            m.fingerprint.delimiter === fingerprint.delimiter &&
            m.fingerprint.columnCount === fingerprint.columnCount
        );

        if (!matchingModel) return [];

        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter;

        const combinedKeywords = [
            ...(matchingModel.parsingRules?.ignoredKeywords || []),
            ...globalKeywords
        ];

        const dataLines = lines.slice(skipRowsStart || 0);

        dataLines.forEach((line, index) => {
            const cols = line.split(delimiter || ';');
            if (cols.length <= Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) return;

            const rawDate = cols[dateColumnIndex];
            const rawDesc = cols[descriptionColumnIndex] || '';
            const rawAmount = cols[amountColumnIndex];
            const rawType = typeColumnIndex !== undefined ? cols[typeColumnIndex] : '';

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);

            if (isoDate && !isNaN(amount)) {
                // REGRA DE FIDELIDADE: 'description' recebe o valor bruto do arquivo.
                // 'cleanedDescription' recebe a versão tratada para o algoritmo de match.
                const cleanedDesc = NameResolver.clean(rawDesc, combinedKeywords);
                const finalType = rawType ? String(rawType).trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);

                transactions.push({
                    id: `db-${index}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc.trim(), // VERDADE ABSOLUTA
                    rawDescription: rawDesc.trim(), // BACKUP DE SEGURANÇA
                    amount: amount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanedDesc, // USADO PARA CONCILIAÇÃO
                    contributionType: finalType
                });
            }
        });

        return transactions;
    }
};

export const SicoobStrategy: BankStrategy = {
    name: 'Sicoob (Extrato PDF)',

    canHandle: (filename, content) => {
        const upper = content.toUpperCase();
        return upper.includes('SICOOB') || 
               (upper.includes('DATA') && upper.includes('HISTÓRICO') && upper.includes('VALOR'));
    },

    parse: (content, yearAnchor, models, globalKeywords = []) => {
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/);
        const headerRegex = /^(\d{2}\/\d{2})\s+(.*?)\s+([\d.,]+[CD]?\*?)$/;

        let currentBlock: { date: string; lines: string[]; rawAmount: string; } | null = null;

        const processBlock = (block: typeof currentBlock) => {
            if (!block) return;
            const isoDate = DateResolver.resolveToISO(block.date, yearAnchor);
            const amountStr = AmountResolver.clean(block.rawAmount);
            const amount = parseFloat(amountStr);

            if (isoDate && !isNaN(amount)) {
                const fullDescription = block.lines.join(' ').trim();
                const cleanedDescription = NameResolver.clean(fullDescription, globalKeywords);
                const type = TypeResolver.resolveFromDescription(fullDescription);

                transactions.push({
                    id: `sicoob-${Date.now()}-${transactions.length}`,
                    date: isoDate,
                    description: fullDescription, // FIDELIDADE
                    rawDescription: fullDescription,
                    amount: amount,
                    originalAmount: block.rawAmount,
                    cleanedDescription: cleanedDescription,
                    contributionType: type
                });
            }
        };

        lines.forEach(line => {
            const match = line.trim().match(headerRegex);
            if (match) {
                if (currentBlock) processBlock(currentBlock);
                currentBlock = { date: match[1], lines: [match[2].trim()], rawAmount: match[3] };
            } else if (currentBlock && line.trim()) {
                currentBlock.lines.push(line.trim());
            }
        });

        if (currentBlock) processBlock(currentBlock);
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico (CSV/Excel)',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords = []) => {
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));

        const dateIdx = DateResolver.identifyDateColumn(rows);
        const amountIdx = AmountResolver.identifyAmountColumn(rows, [dateIdx]);
        const nameIdx = NameResolver.identifyNameColumn(rows, [dateIdx, amountIdx]);

        if (dateIdx === -1 || amountIdx === -1) return [];

        rows.forEach((row, index) => {
            const rawDate = row[dateIdx];
            const rawAmount = row[amountIdx];
            const rawDesc = nameIdx !== -1 ? row[nameIdx] : 'Sem descrição';

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);

            if (isoDate && !isNaN(amount)) {
                const cleanedDesc = NameResolver.clean(rawDesc, globalKeywords);
                transactions.push({
                    id: `gen-${index}-${Date.now()}`,
                    date: isoDate,
                    description: String(rawDesc).trim(), // FIDELIDADE
                    rawDescription: String(rawDesc).trim(),
                    amount: amount,
                    originalAmount: String(rawAmount),
                    cleanedDescription: cleanedDesc,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, SicoobStrategy, GenericStrategy],
    process: (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): { transactions: Transaction[], strategyName: string } => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);
        if (overrideModel) {
            const results = DatabaseModelStrategy.parse(content, yearAnchor, [overrideModel], globalKeywords);
            return { transactions: results, strategyName: `Modelo: ${overrideModel.name}` };
        }
        for (const strategy of StrategyEngine.strategies) {
            if (strategy.name === GenericStrategy.name) continue;
            if (strategy.canHandle(filename, content, models)) {
                const results = strategy.parse(content, yearAnchor, models, globalKeywords);
                if (results.length > 0) return { transactions: results, strategyName: strategy.name };
            }
        }
        return { transactions: GenericStrategy.parse(content, yearAnchor, models, globalKeywords), strategyName: GenericStrategy.name };
    }
};

import { CanonicalDocumentNormalizer } from './CanonicalDocumentNormalizer';

/**
 * SERVIÇO DE DOMÍNIO: FINGERPRINTER (V2 - PROTEGIDA)
 * --------------------------------------------------------------------------
 * Responsável por gerar a identidade estrutural (DNA) de qualquer conteúdo tabular.
 * Implementa isolamento por topologia para evitar conflitos entre modelos similares.
 */

export interface StructuralFingerprint {
    columnCount: number;
    delimiter: string;
    headerHash: string | null;
    dataTopology: string;
    canonicalSignature?: string;
    structuralPattern?: string;
}

export const Fingerprinter = {
    /**
     * Detecta o delimitador de forma estatística.
     */
    detectDelimiter: (line: string): string => {
        const candidates = [';', ',', '\t', '|'];
        const counts = candidates.map(char => ({ 
            char, 
            count: (line || '').split(char).length - 1 
        }));
        counts.sort((a, b) => b.count - a.count);
        return counts[0].count > 0 ? counts[0].char : ';';
    },

    /**
     * Gera o DNA estrutural para reconhecimento independente de formato.
     */
    generate: (content: string): StructuralFingerprint | null => {
        if (!content || typeof content !== 'string') return null;

        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return null;

        const firstLine = lines[0];
        const delimiter = Fingerprinter.detectDelimiter(firstLine);
        const cells = firstLine.split(delimiter);

        // 1. HASH DE CABEÇALHO NORMALIZADO (Imune a espaços e minúsculas)
        const normalizedHeader = firstLine
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '') // Remove acentos
            .replace(/[^A-Z0-9]/gi, '')      // Apenas alfanuméricos
            .toUpperCase();

        const headerHash = normalizedHeader.split('').reduce((a, b) => { 
            a = ((a << 5) - a) + b.charCodeAt(0); 
            return a & a; 
        }, 0).toString(36);

        // 2. ASSINATURA CANÔNICA (Core v3)
        const canonicalSignature = CanonicalDocumentNormalizer.generateSignature(lines);
        const structuralPattern = CanonicalDocumentNormalizer.generateStructuralPattern(lines);

        // 3. TOPOLOGIA DE DADOS (DNA de Tipos)
        // Analisa as primeiras 10 linhas de dados para criar um perfil de tipos (Data, String, Número)
        const dataRows = lines.slice(1, 11);
        let topologyString = "";

        if (dataRows.length > 0) {
            // Pega a linha mais representativa (com mesmo número de colunas do cabeçalho)
            const sampleRow = dataRows.find(r => r.split(delimiter).length === cells.length) || dataRows[0];
            topologyString = sampleRow.split(delimiter).map(c => {
                const val = c.trim().replace(/[R$\s]/g, '').replace(',', '.');
                // Heurística de Tipo
                if (/^\d{2,4}[/-]\d{1,2}[/-]\d{2,4}$/.test(val) || /^\d{1,2}[/-]\d{1,2}$/.test(val)) return 'D'; // Data
                if (!isNaN(parseFloat(val)) && /\d/.test(val)) return 'N'; // Número
                if (val.length === 0) return 'E'; // Vazio (Empty)
                return 'S'; // Texto (String)
            }).join('');
        }

        return { 
            columnCount: cells.length, 
            delimiter, 
            headerHash, 
            dataTopology: topologyString,
            canonicalSignature,
            structuralPattern
        };
    }
};

