interface UseReconciliationProps {
    user: any;
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: any[];
    showToast: (msg: string, type: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: any) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);

    const [uiFeedback, setUiFeedback] = useState({
        loadingAiId: null as string | null,
        aiSuggestion: null as { id: string; name: string } | null,
        isRecompareModalOpen: false,
        pendingTraining: null as any | null
    });

    const { persistTransactions, clearRemoteList } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueMap = new Map<string, MatchResult>();
        results.forEach(r => uniqueMap.set(r.transaction.id, r));
        const uniqueResults = Array.from(uniqueMap.values());

        const incomeResults = uniqueResults.filter(r => 
            r.transaction.amount >= 0 || 
            r.status === ReconciliationStatus.PENDING
        );

        const expenseResults = uniqueResults.filter(r => 
            r.transaction.amount < 0 && 
            r.status !== ReconciliationStatus.PENDING
        );

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            const fileObj = rawFile || new File([content], fileName, { type: 'text/plain' });
            const result = await IngestionOrchestrator.processFile(fileObj, content, fileModels, customIgnoreKeywords);
            const processedTransactions = result.transactions;

            if (processedTransactions.length === 0) {
                showToast("Nenhuma transação encontrada.", "error");
                return;
            }

            await persistTransactions(bankId, processedTransactions);

            setBankStatementFile(prev => {
                const filtered = prev.filter(f => f.bankId !== bankId);
                return [...filtered, { 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile, 
                    processedTransactions,
                    fingerprint: result.fingerprint 
                }];
            });

            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast(`Extrato: ${result.strategyUsed}`, "success");
        } catch (error: any) {
            showToast("Erro ao processar ingestão.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;
        setIsLoading(true);
        try {
            const bankId = 'gmail-sync';
            // UNIFICAÇÃO: O Gmail agora passa pelo mesmo rigor de normalização dos arquivos físicos
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);

            await persistTransactions(bankId, result.transactions);

            setBankStatementFile(prev => [
                ...prev.filter(f => f.bankId !== bankId),
                { 
                    bankId, 
                    fileName: 'Sincronização Gmail', 
                    processedTransactions: result.transactions,
                    content: '',
                    fingerprint: result.fingerprint
                }
            ]);
            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast("Gmail sincronizado e normalizado.", "success");
        } catch (e) {
            showToast("Erro na sincronização virtual.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const removeBankStatementFile = useCallback((bankId: string) => {
        setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
        setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        clearRemoteList(bankId);
    }, [clearRemoteList]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string) => {
        setIsLoading(true);
        try {
            const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
            const church = churches.find(c => c.id === churchId);
            if (contributors.length > 0 && church) {
                setContributorFiles(prev => [...prev.filter(f => f.churchId !== churchId), { church, contributors, fileName, churchId }]);
                showToast("Lista carregada.", "success");
            }
        } catch (error) {
            showToast("Erro ao processar lista.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [churches, customIgnoreKeywords, contributionKeywords, showToast, setIsLoading]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
        showToast("Lista removida.", "success");
    }, [showToast]);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => 
            prev.includes(bankId) ? prev.filter(id => id !== bankId) : [...prev, bankId]
        );
    }, []);

    const handleCompare = useCallback(async (
        overrideType?: ComparisonType, 
        overrideSimilarity?: number, 
        overrideTolerance?: number
    ) => {
        setIsLoading(true);
        try {
            const selectedFiles = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
            const allTransactions = activeReportId ? matchResults.map(r => r.transaction) : selectedFiles.flatMap(f => f.processedTransactions || []);

            if (allTransactions.length === 0 && !activeReportId) {
                showToast("Sem dados para processar.", "error");
                setIsLoading(false);
                return;
            }

            const finalType = overrideType || comparisonType;
            const finalSimilarity = overrideSimilarity !== undefined ? overrideSimilarity : similarityLevel;
            const finalTolerance = overrideTolerance !== undefined ? overrideTolerance : dayTolerance;

            let transactionsToMatch = [...allTransactions];
            if (finalType === 'income') {
                transactionsToMatch = transactionsToMatch.filter(tx => tx.amount >= 0);
            } else if (finalType === 'expenses') {
                transactionsToMatch = transactionsToMatch.filter(tx => tx.amount < 0);
            }

            const results = matchTransactions(
                transactionsToMatch,
                contributorFiles,
                { similarityThreshold: finalSimilarity, dayTolerance: finalTolerance },
                learnedAssociations,
                churches,
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) next[index] = updatedRow;
            else next.push(updatedRow);
            if (updatedRow.status === ReconciliationStatus.IDENTIFIED && updatedRow.contributor?._internalId) {
                const ghostId = `ghost-${updatedRow.contributor._internalId}`;
                const gIdx = next.findIndex(r => r.transaction.id === ghostId && r.status === ReconciliationStatus.PENDING);
                if (gIdx !== -1) next.splice(gIdx, 1);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            if (old.contributor?._internalId) {
                const gId = `ghost-${old.contributor._internalId}`;
                if (!next.some(r => r.transaction.id === gId)) {
                    next.push({
                        transaction: { 
                            id: gId, 
                            date: old.contributor.date || new Date().toISOString().split('T')[0], 
                            description: old.contributor.name, 
                            rawDescription: old.contributor.name, 
                            amount: 0, 
                            cleanedDescription: old.contributor.cleanedName || old.contributor.name, 
                            contributionType: old.contributor.contributionType, 
                            originalAmount: old.contributor.originalAmount || "0.00" 
                        },
                        contributor: old.contributor, 
                        status: ReconciliationStatus.PENDING, 
                        church: old.church, 
                        matchMethod: undefined, 
                        similarity: 0, 
                        contributorAmount: old.contributor.amount 
                    });
                }
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger } from "./monitoringService";

/**
 * Inicialização centralizada seguindo as diretrizes de "new GoogleGenAI({apiKey: process.env.API_KEY})"
 */
const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

// Retry simplificado com backoff exponencial
async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (msg.includes("429") || msg.includes("quota")) {
            if (retries > 0) {
                await new Promise(r => setTimeout(r, delay * 2));
                return callWithSimpleRetry(fn, retries - 1, delay * 2);
            }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * IA TRAINER: Infere o mapeamento de colunas a partir de uma amostra de texto.
 */
export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Analise este fragmento de extrato bancário ou lista e identifique os índices das colunas (começando em 0). 
        Determine qual coluna é a DATA, DESCRIÇÃO (ou NOME), VALOR e TIPO (se houver). 
        Identifique também quantas linhas de cabeçalho devem ser puladas.\n\nAMOSTRA:\n${sampleText.substring(0, 5000)}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        dateColumnIndex: { type: Type.INTEGER },
                        descriptionColumnIndex: { type: Type.INTEGER },
                        amountColumnIndex: { type: Type.INTEGER },
                        typeColumnIndex: { type: Type.INTEGER, nullable: true },
                        skipRowsStart: { type: Type.INTEGER },
                        confidence: { type: Type.NUMBER, description: "0 a 1" }
                    },
                    required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "skipRowsStart"]
                }
            }
        });

        return response.text ? JSON.parse(response.text) : null;
    });
};

/**
 * Extração visual utilizando gemini-2.5-flash-image
 */
export const extractDataFromVisual = async (file: File): Promise<string> => {
    const base64Data = await new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });

    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    { inlineData: { mimeType: file.type, data: base64Data } },
                    { text: "Atue como um motor de OCR financeiro. Extraia as transações para um JSON no formato: { \"rows\": [ { \"date\": \"YYYY-MM-DD\", \"description\": \"string\", \"amount\": number } ] }" }
                ]
            },
            config: { temperature: 0.1 }
        });
        return response.text || "{\"rows\": []}";
    });
};

/**
 * Extração estruturada por exemplo utilizando gemini-3-flash-preview
 */
export const extractStructuredDataByExample = async (rawSnippet: string, userExample: string): Promise<{ rows: any[] }> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Extraia dados financeiros deste documento seguindo o exemplo fornecido.\nEXEMPLO: ${userExample}\nDOCUMENTO: ${rawSnippet.substring(0, 20000)}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING, nullable: true },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER, nullable: true }
                                },
                                required: ["description"]
                            }
                        }
                    },
                    required: ["rows"]
                }
            }
        });
        return response.text ? JSON.parse(response.text) : { rows: [] };
    });
};

/**
 * Sugestão de Contribuintes utilizando gemini-3-flash-preview
 */
export const getAISuggestion = async (transaction: Transaction, contributors: Contributor[]): Promise<string> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Analise: "${transaction.description}". Qual contribuinte melhor se encaixa? Lista: [${contributors.map(c => c.name).join(', ')}]. Responda apenas o nome ou "Nenhuma sugestão clara".`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { temperature: 0.1 }
        });
        return response.text ? response.text.trim() : "Nenhuma sugestão clara";
    });
};

import React, { useState } from 'react';
import { PlayCircleIcon, SparklesIcon } from '../../Icons';
import { inferMappingFromSample } from '../../../services/geminiService';
import { useUI } from '../../../contexts/UIContext';

interface MappingControlsProps {
    mapping: any;
    setMapping: (mapping: any) => void;
    columnCount: number;
    onSimulate: () => void;
    gridData: string[][];
}

export const MappingControls: React.FC<MappingControlsProps> = ({
    mapping,
    setMapping,
    columnCount,
    onSimulate,
    gridData
}) => {
    const [isAiLoading, setIsAiLoading] = useState(false);
    const { showToast } = useUI();

    if (!mapping) return null;

    const columnOptions = Array.from({ length: columnCount }, (_, i) => (
        <option key={i} value={i}>
            Coluna {String.fromCharCode(65 + i)}
        </option>
    ));

    const updateField = (field: string, value: string) => {
        setMapping({ ...mapping, [field]: parseInt(value) });
    };

    const handleAiSuggest = async () => {
        if (!gridData || gridData.length === 0) return;

        setIsAiLoading(true);
        try {
            // Pega as primeiras 15 linhas como amostra para o Gemini
            const sample = gridData.slice(0, 15).map(row => row.join(';')).join('\n');
            const suggestion = await inferMappingFromSample(sample);

            if (suggestion) {
                setMapping({
                    ...mapping,
                    dateColumnIndex: suggestion.dateColumnIndex ?? -1,
                    descriptionColumnIndex: suggestion.descriptionColumnIndex ?? -1,
                    amountColumnIndex: suggestion.amountColumnIndex ?? -1,
                    typeColumnIndex: suggestion.typeColumnIndex ?? -1,
                    skipRowsStart: suggestion.skipRowsStart ?? 0
                });
                showToast(`IA detectou mapeamento com ${Math.round(suggestion.confidence * 100)}% de confiança`, "success");

                // Dispara a simulação automaticamente após o mapeamento
                setTimeout(onSimulate, 500);
            }
        } catch (e: any) {
            console.error("Erro na sugestão da IA:", e);
            showToast("Não foi possível sugerir mapeamento automático.", "error");
        } finally {
            setIsAiLoading(false);
        }
    };

    const ControlItem = ({ label, field, value, color }: { label: string, field: string, value: number, color: string }) => (
        <div className={`flex items-center gap-1.5 bg-white dark:bg-slate-800 rounded-full px-3 py-1 border border-slate-200 dark:border-slate-700 shadow-sm`}>
            <label className={`text-[9px] font-bold uppercase ${color}`}>{label}</label>
            <select 
                value={value} 
                onChange={(e) => updateField(field, e.target.value)}
                className="bg-transparent text-[11px] font-bold outline-none w-20 cursor-pointer text-slate-700 dark:text-slate-200"
            >
                <option value="-1">Nenhum</option>
                {columnOptions}
            </select>
        </div>
    );

    return (
        <div className="flex flex-wrap gap-2 items-center flex-1">
            <ControlItem 
                label="Data" 
                field="dateColumnIndex" 
                value={mapping.dateColumnIndex} 
                color="text-blue-600" 
            />
            <ControlItem 
                label="Descrição" 
                field="descriptionColumnIndex" 
                value={mapping.descriptionColumnIndex} 
                color="text-purple-600" 
            />
            <ControlItem 
                label="Valor" 
                field="amountColumnIndex" 
                value={mapping.amountColumnIndex} 
                color="text-emerald-600" 
            />

            <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1 hidden sm:block"></div>

            <button 
                onClick={handleAiSuggest}
                disabled={isAiLoading}
                className={`
                    flex items-center gap-2 px-5 py-1.5 rounded-full text-[10px] font-bold uppercase transition-all shadow-md active:scale-95
                    ${isAiLoading 
                        ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                        : 'bg-gradient-to-r from-violet-600 to-indigo-600 text-white hover:shadow-violet-500/30'
                    }
                `}
            >
                {isAiLoading ? (
                    <svg className="animate-spin h-3 w-3 text-slate-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <SparklesIcon className="w-3.5 h-3.5" />
                )}
                <span>{isAiLoading ? 'Lendo...' : 'Sugerir com IA'}</span>
            </button>

            <button 
                onClick={onSimulate}
                className="flex items-center gap-2 px-5 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full text-[10px] font-bold uppercase shadow-md transition-all active:scale-95"
            >
                <PlayCircleIcon className="w-4 h-4" />
                <span>Simular</span>
            </button>
        </div>
    );
};

