import React, { useRef, useState, useEffect, forwardRef, useImperativeHandle } from 'react';
import { UploadIcon, CheckCircleIcon, XMarkIcon } from './Icons';
import { useUI } from '../contexts/UIContext';

let pdfjsLib: any = null;
let mammoth: any = null;
let XLSX: any = null;

export interface FileUploaderHandle {
    open: () => void;
}

interface FileUploaderProps {
  title: string;
  onFileUpload: (content: string, fileName: string, rawFile: File) => void;
  id: string;
  isUploaded: boolean;
  uploadedFileName: string | null;
  disabled?: boolean;
  onDelete?: () => void;
  customTrigger?: (props: { onClick: (e: React.MouseEvent) => void, disabled: boolean, isParsing: boolean }) => React.ReactNode;
  onParsingStatusChange?: (isParsing: boolean) => void;
  useLocalLoadingOnly?: boolean; 
}

export const FileUploader = forwardRef<FileUploaderHandle, FileUploaderProps>(({ 
    title, 
    onFileUpload, 
    id, 
    isUploaded, 
    uploadedFileName, 
    disabled = false, 
    onDelete, 
    customTrigger,
    onParsingStatusChange,
    useLocalLoadingOnly = false
}, ref) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isParsing, setIsParsing] = useState(false);
  const { setIsLoading, setParsingProgress } = useUI() as any;

  useImperativeHandle(ref, () => ({
      open: () => {
          if (!disabled && !isParsing) {
              fileInputRef.current?.click();
          }
      }
  }));

  const ensureLibsLoaded = async () => {
    try {
        if (!pdfjsLib) {
            try {
                const pdfModule = await import('pdfjs-dist');
                const lib = pdfModule.default || pdfModule;
                if (!lib.GlobalWorkerOptions.workerSrc) {
                    const version = lib.version || '3.11.174';
                    lib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${version}/pdf.worker.min.js`;
                }
                pdfjsLib = lib;
            } catch (e) {}
        }
        if (!mammoth) { try { const mod = await import('mammoth'); mammoth = mod.default || mod; } catch (e) {} }
        if (!XLSX) { try { const mod = await import('xlsx'); XLSX = mod.default || mod; } catch (e) {} }
    } catch (e) {}
  };

  useEffect(() => { ensureLibsLoaded(); }, []);

  useEffect(() => {
      if (onParsingStatusChange) {
          onParsingStatusChange(isParsing);
      }
      if (!useLocalLoadingOnly) {
          setIsLoading(isParsing);
      }
  }, [isParsing, onParsingStatusChange, setIsLoading, useLocalLoadingOnly]);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    processFile(file);
  };

  const processFile = async (file: File) => {
    setIsParsing(true);
    if (setParsingProgress) setParsingProgress({ current: 0, total: 0, label: 'Iniciando...' });

    try {
        await ensureLibsLoaded();
        const fileNameLower = file.name.toLowerCase();
        const fileBuffer = await file.arrayBuffer();
        let extractedText = '';

        if (fileNameLower.endsWith('.pdf')) {
             if (!pdfjsLib) throw new Error("Biblioteca PDF não carregada.");
             const loadingTask = pdfjsLib.getDocument(new Uint8Array(fileBuffer));
             const pdf = await loadingTask.promise;
             const totalPages = pdf.numPages;

             for (let i = 1; i <= totalPages; i++) {
                 if (setParsingProgress) setParsingProgress({ current: i, total: totalPages, label: `Extraindo texto: Página ${i}/${totalPages}` });
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const items = textContent.items as any[];
                 extractedText += items.map(it => it.str).join(' ') + '\n';
             }
        } else if (fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls')) {
            if (!XLSX) throw new Error("Excel lib missing");
            const workbook = XLSX.read(new Uint8Array(fileBuffer), { type: 'array' });
            const worksheet = workbook.Sheets[workbook.SheetNames[0]];
            extractedText = XLSX.utils.sheet_to_csv(worksheet, { FS: ";" }); 
        } else if (/\.(jpg|jpeg|png|webp)$/i.test(fileNameLower)) {
            // Para imagens, o conteúdo de texto é gerado depois via Gemini no hook,
            // mas precisamos passar algo para o onFileUpload
            extractedText = "[IMAGE_FILE]";
        } else {
            extractedText = new TextDecoder('utf-8').decode(fileBuffer);
        }

        onFileUpload(extractedText, file.name, file);
    } catch (error: any) {
        alert(`Erro: ${error.message}`);
    } finally {
        setIsParsing(false);
        if (setParsingProgress) setParsingProgress(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (!disabled && !isParsing) fileInputRef.current?.click();
  };

  if (customTrigger) {
      return (
          <div className="flex-shrink-0">
              <input type="file" id={id} ref={fileInputRef} className="hidden" onChange={handleFileChange} disabled={disabled || isParsing} accept=".csv,.txt,.xlsx,.xls,.pdf,.jpg,.jpeg,.png,.webp" />
              {customTrigger({ onClick: handleClick, disabled: disabled || isParsing, isParsing })}
          </div>
      );
  }

  return (
    <div className="flex-shrink-0">
      <input type="file" id={id} ref={fileInputRef} className="hidden" onChange={handleFileChange} disabled={disabled || isParsing} accept=".csv,.txt,.xlsx,.xls,.pdf,.jpg,.jpeg,.png,.webp" />
      <button type="button" onClick={handleClick} disabled={disabled || isParsing} className={`group inline-flex items-center justify-center space-x-1.5 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-wide transition-all ${disabled ? 'bg-slate-100 text-slate-400' : 'text-white bg-emerald-600 hover:bg-emerald-500 shadow-sm'}`}>
         {isParsing ? <><svg className="animate-spin h-3 w-3 text-white mr-1" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg><span>Lendo...</span></> : <><UploadIcon className="w-3 h-3" /><span>{title}</span></>}
      </button>
    </div>
  );
});

import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { detectDelimiter, generateFingerprint } from '../services/processingService';
import { extractDataFromVisual } from '../services/geminiService';
import { FileModel } from '../types';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isImage: boolean;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isImage, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            processingRef.current = null;
            return;
        }

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                if (isImage && activeFile.rawFile) {
                    setIsAiProcessing(true);
                    const aiResult = await extractDataFromVisual(activeFile.rawFile);
                    try {
                        const parsed = JSON.parse(aiResult);
                        if (parsed?.rows) {
                            loadedRows = parsed.rows.map((r: any) => [
                                String(r.date || ''),
                                String(r.description || ''),
                                r.amount ? String(r.amount) : '',
                                String(r.reference || '')
                            ]);

                            setActiveMapping({
                                dateColumnIndex: 0,
                                descriptionColumnIndex: 1,
                                amountColumnIndex: 2,
                                typeColumnIndex: 3,
                                skipRowsStart: 0
                            });
                        }
                    } catch (e) {
                        console.error("Erro ao parsear resposta da IA:", e);
                    }
                } else if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(wb.Sheets[wb.SheetNames[0]], { header: 1, defval: '' });
                } else {
                    // Texto puro ou PDF extraído
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        // Tenta descobrir o delimitador (para PDF/TXT costuma ser espaço ou quebra de linha)
                        // Se o conteúdo for o resultado de um PDF extraído, as linhas já estão lá
                        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
                        if (lines.length > 0) {
                            // Se as linhas parecerem colunas separadas por múltiplos espaços (comum em PDF)
                            const firstLine = lines[0];
                            const delimiter = detectDelimiter(firstLine);

                            // Se o delimitador detectado for muito fraco, tenta split por múltiplos espaços (PDF/OCR Style)
                            if (delimiter === ';' || delimiter === ',') {
                                loadedRows = lines.map((l: string) => l.split(delimiter));
                            } else {
                                loadedRows = lines.map((l: string) => l.split(/\s{2,}/));
                            }
                        }
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);

                    const sampleContent = activeFile.content || loadedRows.slice(0, 10).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContent);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else if (!isImage && !activeMapping) {
                        setActiveMapping({
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no pré-processamento:", err);
            } finally {
                setIsGridLoading(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, isImage, initialModel]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};

import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { detectDelimiter, generateFingerprint } from '../services/processingService';
import { extractDataFromVisual } from '../services/geminiService';
import { FileModel } from '../types';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isImage: boolean;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isImage, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            processingRef.current = null;
            return;
        }

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                if (isImage && activeFile.rawFile) {
                    setIsAiProcessing(true);
                    // Dispara extração visual via Gemini
                    const aiResult = await extractDataFromVisual(activeFile.rawFile);
                    try {
                        const parsed = JSON.parse(aiResult);
                        if (parsed?.rows && Array.isArray(parsed.rows)) {
                            loadedRows = parsed.rows.map((r: any) => [
                                String(r.date || ''),
                                String(r.description || ''),
                                r.amount ? String(r.amount) : '',
                                String(r.reference || '')
                            ]);

                            // Mapeamento automático para o resultado da IA
                            setActiveMapping({
                                dateColumnIndex: 0,
                                descriptionColumnIndex: 1,
                                amountColumnIndex: 2,
                                typeColumnIndex: 3,
                                skipRowsStart: 0
                            });
                        }
                    } catch (e) {
                        console.error("Erro ao parsear resposta da IA:", e);
                    }
                } else if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(wb.Sheets[wb.SheetNames[0]], { header: 1, defval: '' });
                } else {
                    // Texto puro ou PDF extraído
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
                        if (lines.length > 0) {
                            const firstLine = lines[0];
                            const delimiter = detectDelimiter(firstLine);

                            if (delimiter === ';' || delimiter === ',') {
                                loadedRows = lines.map((l: string) => l.split(delimiter));
                            } else {
                                loadedRows = lines.map((l: string) => l.split(/\s{2,}/));
                            }
                        }
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);

                    const sampleContent = activeFile.content || loadedRows.slice(0, 10).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContent);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else if (!isImage && !activeMapping) {
                        setActiveMapping({
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no pré-processamento:", err);
            } finally {
                setIsGridLoading(false);
                setIsAiProcessing(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, isImage, initialModel]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};

import React from 'react';
import { SparklesIcon, ExclamationTriangleIcon } from '../../Icons';

interface SpreadsheetRendererProps {
    data: string[][];
    isLoading?: boolean;
    detectedMapping?: any;
    isAiProcessed?: boolean;
    isImage?: boolean; // Nova prop
}

export const SpreadsheetRenderer: React.FC<SpreadsheetRendererProps> = ({ 
    data, 
    isLoading, 
    detectedMapping, 
    isAiProcessed,
    isImage = false
}) => {
    const getColumnLabel = (index: number) => {
        let label = '';
        let i = index;
        while (i >= 0) {
            label = String.fromCharCode((i % 26) + 65) + label;
            i = Math.floor(i / 26) - 1;
        }
        return label;
    };

    const getColumnHighlight = (index: number) => {
        if (!detectedMapping) return '';
        if (index === detectedMapping.dateColumnIndex) return 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800';
        if (index === detectedMapping.amountColumnIndex) return 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800';
        if (index === detectedMapping.descriptionColumnIndex) return 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800';
        return '';
    };

    const getColumnHeaderHighlight = (index: number) => {
        if (!detectedMapping) return '';
        if (index === detectedMapping.dateColumnIndex) return 'bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300';
        if (index === detectedMapping.amountColumnIndex) return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900 dark:text-emerald-300';
        if (index === detectedMapping.descriptionColumnIndex) return 'bg-purple-100 text-purple-700 dark:bg-purple-900 dark:text-purple-300';
        return '';
    }

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 space-y-4 bg-slate-50 dark:bg-slate-900">
                <div className="relative">
                    <div className="absolute inset-0 bg-brand-blue blur-xl opacity-20 rounded-full animate-pulse"></div>
                    <SparklesIcon className="w-12 h-12 text-brand-blue relative z-10 animate-bounce" />
                </div>
                <div>
                    <p className="text-xs font-bold uppercase tracking-widest text-slate-600 dark:text-slate-300">Processando Documento</p>
                    <p className="text-[10px] text-slate-400 text-center mt-1">
                        {isAiProcessed || isImage ? 'A inteligência artificial está interpretando o visual...' : 'Lendo estrutura do arquivo...'}
                    </p>
                </div>
            </div>
        );
    }

    if (!data || data.length === 0) {
        // Se for imagem, não mostramos erro, pois o ImageRenderer deve estar por cima ou a grid vai carregar
        if (isImage) return null;

        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center bg-slate-50 dark:bg-slate-900/50">
                <ExclamationTriangleIcon className="w-12 h-12 mb-3 opacity-20" />
                <p className="text-sm font-bold text-slate-500 dark:text-slate-300">Visualização indisponível</p>
            </div>
        );
    }

    const maxCols = data.reduce((max, row) => Math.max(max, row.length), 0);
    const colIndices = Array.from({ length: maxCols }, (_, i) => i);

    return (
        <div className="absolute inset-0 overflow-auto custom-scrollbar bg-[#f8f9fa] dark:bg-[#1e1e1e] select-text">
            {isAiProcessed && (
                <div className="sticky left-0 top-0 z-40 bg-purple-100 dark:bg-purple-900/50 text-purple-700 dark:text-purple-300 px-3 py-1 text-[9px] font-bold uppercase tracking-wide border-b border-purple-200 dark:border-purple-800 flex items-center gap-2">
                    <SparklesIcon className="w-3 h-3" /> Conteúdo Interpretado por IA
                </div>
            )}
            <table className="border-collapse table-fixed min-w-full">
                <thead className="sticky top-0 z-20">
                    <tr>
                        <th className="w-10 min-w-[40px] bg-[#e6e6e6] dark:bg-[#333] border-r border-b border-[#c0c0c0] dark:border-[#555] sticky left-0 z-30"></th>
                        {colIndices.map(colIndex => (
                            <th key={colIndex} className={`bg-[#f0f0f0] dark:bg-[#2d2d2d] border-r border-b border-[#d4d4d4] dark:border-[#555] text-center text-[10px] font-bold text-slate-600 dark:text-slate-300 h-6 min-w-[100px] select-none ${getColumnHeaderHighlight(colIndex)}`}>
                                {getColumnLabel(colIndex)}
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {data.slice(0, 500).map((row, rowIndex) => (
                        <tr key={rowIndex} className="h-6">
                            <td className="sticky left-0 z-10 bg-[#f0f0f0] dark:bg-[#2d2d2d] border-r border-b border-[#d4d4d4] dark:border-[#555] text-center text-[10px] font-bold text-slate-600 dark:text-slate-300 select-none w-10">
                                {rowIndex + 1}
                            </td>
                            {colIndices.map(colIndex => (
                                <td 
                                    key={`${rowIndex}-${colIndex}`} 
                                    className={`border-r border-b border-[#e0e0e0] dark:border-[#444] px-2 py-0.5 text-xs text-slate-800 dark:text-slate-200 whitespace-nowrap overflow-hidden text-ellipsis hover:bg-slate-100 dark:hover:bg-slate-800 cursor-cell ${getColumnHighlight(colIndex)}`}
                                    title={row[colIndex]}
                                >
                                    {row[colIndex]}
                                </td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

import React, { useState, useMemo, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext'; 
import { useAuth } from '../../contexts/AuthContext';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import { CloudArrowUpIcon, DocumentArrowDownIcon } from '../Icons';

// Sub-componentes
import { PDFRenderer } from './preprocessor/PDFRenderer';
import { ImageRenderer } from './preprocessor/ImageRenderer';
import { SpreadsheetRenderer } from './preprocessor/SpreadsheetRenderer';
import { SimulatedResultsTable } from './preprocessor/SimulatedResultsTable';
import { MappingControls } from './preprocessor/MappingControls';
import { TeachingBanner } from './preprocessor/TeachingBanner';
import { PreprocessorHeader } from './preprocessor/PreprocessorHeader';

// Hooks
import { useFileProcessing } from '../../hooks/useFileProcessing';
import { useSimulation } from '../../hooks/useSimulation';
import { useAIPatternTeacher, LearningPackage } from '../../hooks/useAIPatternTeacher';
import { FileUploader } from '../FileUploader';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const { effectiveIgnoreKeywords, contributionKeywords } = useContext(AppContext);

    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile: File } | null>(null);
    const activeFile = initialFile || uploadedFile || null;

    const isPdf = useMemo(() => activeFile?.fileName?.toLowerCase().endsWith('.pdf'), [activeFile]);
    const isImage = useMemo(() => /\.(jpg|jpeg|png|webp)$/i.test(activeFile?.fileName || ''), [activeFile]);
    const cleaningKeywords = useMemo(() => [...effectiveIgnoreKeywords, ...contributionKeywords], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading, isAiProcessing, 
        activeMapping, setActiveMapping, detectedFingerprint 
    } = useFileProcessing({ activeFile, initialModel, isImage, isPdf });

    const {
        processedTransactions, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ gridData, activeMapping, cleaningKeywords });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ gridData, setGridData, setActiveMapping, showToast });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    // Força a exibição de mapeamento vazio se o arquivo estiver presente
    useEffect(() => {
        if (activeFile && !activeMapping && !isGridLoading && !isImage) {
            setActiveMapping({
                dateColumnIndex: -1,
                descriptionColumnIndex: -1,
                amountColumnIndex: -1,
                skipRowsStart: 0
            });
        }
    }, [activeFile, activeMapping, isGridLoading, setActiveMapping, isImage]);

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.slice(0, 50).map(row => row.join(';')).join('\n');
            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: detectedFingerprint, 
                mapping: activeMapping, 
                parsingRules: { 
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [], 
                    rowFilters: [] 
                }, 
                snippet: finalSnippet, 
                lastUsedAt: new Date().toISOString(), 
                status: approvalStatus, 
                approvedBy: approvalStatus === 'approved' ? user.id : undefined, 
                approvedAt: approvalStatus === 'approved' ? new Date().toISOString() : undefined 
            };
            const saved = await modelService.saveModel(modelData);
            showToast(approvalStatus === 'approved' ? "Modelo aprovado com sucesso!" : "Layout salvo como rascunho.", "success");
            if (onSuccess && saved) {
                onSuccess(saved as FileModel, processedTransactions.filter(t => t.isValid));
            } else {
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao persistir aprendizado no servidor.", "error"); 
        } finally { 
            setIsSavingModel(false); 
        }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, processedTransactions, onSuccess, onClose, showToast]);

    const handleInternalUpload = (content: string, fileName: string, rawFile: File) => {
        setUploadedFile({ content, fileName, rawFile });
    };

    const canApprove = processedTransactions.length > 0 && mode !== 'test';

    return createPortal(
        <div className="fixed inset-0 z-[9999] bg-[#050B14]/95 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Novo Layout'} 
                    canApprove={canApprove} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
                />

                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden min-h-0">
                    {/* COLUNA ESQUERDA: ARQUIVO ORIGINAL */}
                    <section className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-[#0B1120] relative">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm flex gap-3 items-center z-20 shrink-0 min-h-[56px]">
                            {activeFile ? (
                                <MappingControls 
                                    mapping={activeMapping} 
                                    setMapping={setActiveMapping} 
                                    columnCount={gridData[0]?.length || 0} 
                                    onSimulate={runSimulation}
                                    gridData={gridData}
                                />
                            ) : (
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-2">Aguardando arquivo...</div>
                            )}
                        </div>

                        <div className="flex-1 relative overflow-hidden">
                            {isGridLoading || isAiProcessing ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-900 z-30">
                                     <div className="animate-spin rounded-full h-10 w-10 border-4 border-indigo-500 border-t-transparent mb-4"></div>
                                     <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                         {isImage ? 'A IA está lendo a foto...' : 'Processando Documento...'}
                                     </p>
                                </div>
                            ) : !activeFile ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                                    <div className="w-20 h-20 bg-indigo-50 dark:bg-indigo-900/20 rounded-3xl flex items-center justify-center mb-6 text-indigo-500 shadow-inner">
                                        <CloudArrowUpIcon className="w-10 h-10" />
                                    </div>
                                    <h4 className="text-xl font-black text-slate-800 dark:text-white mb-2">Treinar Novo Layout</h4>
                                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm mb-8 leading-relaxed">
                                        Suba um extrato para ensinar o sistema a extrair os dados automaticamente na próxima vez.
                                    </p>
                                    <FileUploader 
                                        id="internal-preprocessor-upload"
                                        title="Selecionar Arquivo"
                                        onFileUpload={handleInternalUpload}
                                        isUploaded={false}
                                        uploadedFileName={null}
                                        useLocalLoadingOnly={true} 
                                    />
                                </div>
                            ) : (
                                isPdf && activeFile?.rawFile ? <PDFRenderer file={activeFile.rawFile} /> : 
                                isImage && activeFile?.rawFile && gridData.length === 0 ? <ImageRenderer file={activeFile.rawFile} /> : 
                                <SpreadsheetRenderer data={gridData} isLoading={false} detectedMapping={activeMapping} isAiProcessed={isAiProcessing} isImage={isImage} />
                            )}
                        </div>
                    </section>

                    {/* COLUNA DIREITA: SIMULAÇÃO DO MODELO */}
                    <section className="flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0F172A] border-l border-slate-200 dark:border-slate-800">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 flex items-center justify-between shrink-0">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                                <DocumentArrowDownIcon className="w-4 h-4" /> Prévia da Simulação
                            </h4>
                            <span className="text-[9px] font-bold text-slate-400 bg-white dark:bg-slate-800 px-2 py-0.5 rounded-full border border-slate-200 dark:border-slate-700">
                                {processedTransactions.length} linhas detectadas
                            </span>
                        </div>

                        <TeachingBanner isVisible={!!learnedPatternSource} isProcessing={isInferringMapping} onApply={handleApplyCorrectionPattern} />

                        <div className="flex-1 overflow-auto custom-scrollbar">
                            {!activeFile ? (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center opacity-40">
                                    <DocumentArrowDownIcon className="w-12 h-12 mb-3" />
                                    <p className="text-xs font-bold uppercase tracking-widest">Aguardando dados para simulação</p>
                                </div>
                            ) : (
                                <SimulatedResultsTable 
                                    transactions={processedTransactions} 
                                    activeMapping={!!activeMapping && activeMapping.dateColumnIndex !== -1} 
                                    isTestMode={mode === 'test'} 
                                    editingRowIndex={editingRowIndex} 
                                    editingRowData={editingRowData} 
                                    onStartEdit={startEdit} 
                                    onSaveRow={() => saveRow((original, corrected) => setLearnedPatternSource({ originalRaw: original, corrected }))} 
                                    onCancelEdit={cancelEdit} 
                                    onUpdateEditingData={setEditingRowData} 
                                />
                            )}
                        </div>
