import React, { useState } from 'react';
import { PlayCircleIcon, SparklesIcon } from '../../Icons';
import { inferMappingFromSample } from '../../../services/geminiService';
import { useUI } from '../../../contexts/UIContext';

interface MappingControlsProps {
    mapping: any;
    setMapping: (mapping: any) => void;
    columnCount: number;
    onSimulate: () => void;
    gridData: string[][];
}

export const MappingControls: React.FC<MappingControlsProps> = ({
    mapping,
    setMapping,
    columnCount,
    onSimulate,
    gridData
}) => {
    const [isAiLoading, setIsAiLoading] = useState(false);
    const { showToast } = useUI();

    if (!mapping) return null;

    // Se não houver colunas (imagem ainda processando), mostra opção vazia mas mantém o layout
    const columnOptions = columnCount > 0 ? Array.from({ length: columnCount }, (_, i) => (
        <option key={i} value={i}>
            Coluna {String.fromCharCode(65 + i)}
        </option>
    )) : [<option key="empty" value="-1" disabled>Aguardando IA...</option>];

    const updateField = (field: string, value: string) => {
        setMapping({ ...mapping, [field]: parseInt(value) });
    };

    const handleAiSuggest = async () => {
        if (!gridData || gridData.length === 0) {
            showToast("Aguarde a IA carregar os dados da imagem primeiro.", "error");
            return;
        }

        setIsAiLoading(true);
        try {
            const sample = gridData.slice(0, 15).map(row => row.join(';')).join('\n');
            const suggestion = await inferMappingFromSample(sample);

            if (suggestion) {
                setMapping({
                    ...mapping,
                    dateColumnIndex: suggestion.dateColumnIndex ?? -1,
                    descriptionColumnIndex: suggestion.descriptionColumnIndex ?? -1,
                    amountColumnIndex: suggestion.amountColumnIndex ?? -1,
                    typeColumnIndex: suggestion.typeColumnIndex ?? -1,
                    skipRowsStart: suggestion.skipRowsStart ?? 0
                });
                showToast(`IA detectou mapeamento com ${Math.round(suggestion.confidence * 100)}% de confiança`, "success");
                setTimeout(onSimulate, 500);
            }
        } catch (e: any) {
            showToast("Não foi possível sugerir mapeamento automático.", "error");
        } finally {
            setIsAiLoading(false);
        }
    };

    const ControlItem = ({ label, field, value, color }: { label: string, field: string, value: number, color: string }) => (
        <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 rounded-full px-3 py-1 border border-slate-200 dark:border-slate-700 shadow-sm">
            <label className={`text-[9px] font-bold uppercase ${color}`}>{label}</label>
            <select 
                value={value} 
                onChange={(e) => updateField(field, e.target.value)}
                className="bg-transparent text-[11px] font-bold outline-none w-20 cursor-pointer text-slate-700 dark:text-slate-200"
            >
                <option value="-1">Nenhum</option>
                {columnOptions}
            </select>
        </div>
    );

    return (
        <div className="flex flex-wrap gap-2 items-center flex-1">
            <ControlItem 
                label="Data" 
                field="dateColumnIndex" 
                value={mapping.dateColumnIndex} 
                color="text-blue-600" 
            />
            <ControlItem 
                label="Descrição" 
                field="descriptionColumnIndex" 
                value={mapping.descriptionColumnIndex} 
                color="text-purple-600" 
            />
            <ControlItem 
                label="Valor" 
                field="amountColumnIndex" 
                value={mapping.amountColumnIndex} 
                color="text-emerald-600" 
            />

            <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1 hidden sm:block"></div>

            <button 
                onClick={handleAiSuggest}
                disabled={isAiLoading || gridData.length === 0}
                className={`
                    flex items-center gap-2 px-5 py-1.5 rounded-full text-[10px] font-bold uppercase transition-all shadow-md active:scale-95
                    ${isAiLoading || gridData.length === 0
                        ? 'bg-slate-100 text-slate-400 cursor-not-allowed opacity-50' 
                        : 'bg-gradient-to-r from-violet-600 to-indigo-600 text-white hover:shadow-violet-500/30'
                    }
                `}
            >
                {isAiLoading ? (
                    <svg className="animate-spin h-3 w-3 text-slate-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <SparklesIcon className="w-3.5 h-3.5" />
                )}
                <span>{isAiLoading ? 'Lendo...' : 'Sugerir com IA'}</span>
            </button>

            <button 
                onClick={onSimulate}
                disabled={gridData.length === 0}
                className="flex items-center gap-2 px-5 py-1.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-full text-[10px] font-bold uppercase shadow-md transition-all active:scale-95"
            >
                <PlayCircleIcon className="w-4 h-4" />
                <span>Simular</span>
            </button>
        </div>
    );
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { RowValidator } from '../core/processors/RowValidator';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(() => {
        // Se a grid ainda está vazia (comum em imagens em processamento), reseta as transações mas permite o renderizador do pai agir
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || {
            dateColumnIndex: -1,
            descriptionColumnIndex: -1,
            amountColumnIndex: -1,
            skipRowsStart: 0
        };

        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = mapping;

        const newTransactions: SafeTransaction[] = [];
        const yearAnchor = new Date().getFullYear();

        const sampleData = gridData.slice(0, 50);

        sampleData.forEach((cols, index) => {
            if (!RowValidator.isPotentialRow(cols)) return;

            const isSkipped = index < (skipRowsStart || 0);

            if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                newTransactions.push({ 
                    id: `sim-raw-${index}`, 
                    date: "---", 
                    description: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    rawDescription: cols.join('|'), 
                    amount: 0, 
                    originalAmount: "0.00", 
                    cleanedDescription: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    contributionType: "BRUTO", 
                    sourceIndex: index, 
                    isValid: false, 
                    status: 'pending' 
                });
                return;
            }

            const rawDate = cols[dateColumnIndex] || '';
            const rawDesc = cols[descriptionColumnIndex] || '';
            const rawAmount = cols[amountColumnIndex] || '';
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? cols[typeColumnIndex] : '';

            let isoDate = '', amount = 0, cleanedDesc = '', finalType = '', isValid = false, status: SafeTransaction['status'] = 'pending';

            if (isSkipped) { 
                status = 'ignored';
                cleanedDesc = cols.join(' | ').substring(0, 100);
            } else {
                isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const amountStr = AmountResolver.clean(rawAmount);
                amount = parseFloat(amountStr);

                if (!!isoDate && !isNaN(amount) && rawDesc.trim().length > 0) {
                    cleanedDesc = NameResolver.clean(rawDesc, cleaningKeywords);
                    finalType = rawType ? String(rawType).trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);
                    isValid = true; 
                    status = 'valid';
                } else {
                    status = 'error';
                    cleanedDesc = rawDesc || cols.filter(c => !!c).join(' | ').substring(0, 60);
                }
            }

            newTransactions.push({ 
                id: `sim-${index}`, 
                date: isValid ? isoDate : (rawDate || "---"), 
                description: rawDesc || "---", 
                rawDescription: rawDesc || "---", 
                amount, 
                originalAmount: String(rawAmount), 
                cleanedDescription: cleanedDesc, 
                contributionType: finalType, 
                sourceIndex: index, 
                isValid, 
                status 
            });
        });

        setProcessedTransactions(newTransactions);
    }, [gridData, activeMapping, cleaningKeywords]);

    useEffect(() => {
        const dataKey = `${gridData.length}-${gridData[0]?.length || 0}`;
        const mappingKey = JSON.stringify(activeMapping);

        if (dataKey !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataKey;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    const startEdit = (tx: SafeTransaction, idx: number) => {
        setEditingRowIndex(idx);
        setEditingRowData({ ...tx });
    };

    const saveRow = (onLearned?: (original: string[], corrected: SafeTransaction) => void) => {
        if (editingRowIndex !== null && editingRowData) {
            setProcessedTransactions(prev => {
                const n = [...prev];
                n[editingRowIndex] = { ...editingRowData, status: 'edited', isValid: true };
                return n;
            });

            if (onLearned && editingRowData.sourceIndex !== undefined) {
                onLearned(gridData[editingRowData.sourceIndex], editingRowData);
            }
            setEditingRowIndex(null);
        }
    };

    const cancelEdit = () => setEditingRowIndex(null);

    return {
        processedTransactions,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit,
        saveRow,
        cancelEdit
    };
};

