                                     <div className="animate-spin rounded-full h-10 w-10 border-4 border-indigo-500 border-t-transparent mb-4"></div>
                                     <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                         A IA está interpretando o padrão visual...
                                     </p>
                                </div>
                            ) : !activeFile ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                                    <div className="w-20 h-20 bg-indigo-50 dark:bg-indigo-900/20 rounded-3xl flex items-center justify-center mb-6 text-indigo-500 shadow-inner">
                                        <PhotoIcon className="w-10 h-10" />
                                    </div>
                                    <h4 className="text-xl font-black text-slate-800 dark:text-white mb-2">Treinar via Foto</h4>
                                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm mb-8 leading-relaxed">
                                        Suba uma imagem ou foto do extrato para que a IA aprenda a reconhecer este padrão estrutural automaticamente.
                                    </p>
                                    <FileUploader 
                                        id="internal-preprocessor-upload"
                                        title="Selecionar Imagem"
                                        onFileUpload={handleInternalUpload}
                                        isUploaded={false}
                                        uploadedFileName={null}
                                        useLocalLoadingOnly={true} 
                                    />
                                    <p className="text-[10px] text-slate-400 mt-4 uppercase font-bold tracking-tighter">Formatos aceitos: JPG, PNG, WEBP</p>
                                </div>
                            ) : (
                                <ImageRenderer file={activeFile.rawFile} />
                            )}
                        </div>
                    </section>

                    {/* COLUNA DIREITA: SIMULAÇÃO DO MODELO (Extração Visual) */}
                    <section className="flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0F172A] border-l border-slate-200 dark:border-slate-800">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 flex items-center justify-between shrink-0">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                                <SparklesIcon className="w-4 h-4 text-indigo-500" /> Resultado da Visão Computacional
                            </h4>
                            <span className="text-[9px] font-bold text-slate-400 bg-white dark:bg-slate-800 px-2 py-0.5 rounded-full border border-slate-200 dark:border-slate-700">
                                {processedTransactions.length} registros detectados
                            </span>
                        </div>

                        <TeachingBanner isVisible={!!learnedPatternSource} isProcessing={isInferringMapping} onApply={handleApplyCorrectionPattern} />

                        <div className="flex-1 overflow-auto custom-scrollbar">
                            {!activeFile ? (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center opacity-40">
                                    <DocumentArrowDownIcon className="w-12 h-12 mb-3" />
                                    <p className="text-xs font-bold uppercase tracking-widest">Aguardando mapeamento visual</p>
                                </div>
                            ) : (
                                <SimulatedResultsTable 
                                    transactions={processedTransactions} 
                                    activeMapping={!!activeMapping} 
                                    isTestMode={mode === 'test'} 
                                    editingRowIndex={editingRowIndex} 
                                    editingRowData={editingRowData} 
                                    onStartEdit={startEdit} 
                                    onSaveRow={() => saveRow((original, corrected) => setLearnedPatternSource({ originalRaw: original, corrected }))} 
                                    onCancelEdit={cancelEdit} 
                                    onUpdateEditingData={setEditingRowData} 
                                />
                            )}
                        </div>
                    </section>
                </div>

                {showNameModal && (
                    <div className="fixed inset-0 z-[10000] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm border border-white/10 animate-scale-in text-center">
                            <h3 className="text-xl font-black text-slate-800 dark:text-white mb-2">Nomear Padrão Visual</h3>
                            <p className="text-xs text-slate-500 mb-6 font-medium">Dê um nome amigável para este modelo reconhecido por imagem.</p>
                            <input type="text" autoFocus value={modelName} onChange={e => setModelName(e.target.value)} className="w-full p-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-800 dark:text-white mb-6 outline-none font-bold" placeholder="Ex: Extrato Inter PJ - Foto" />
                            <div className="flex gap-3">
                                <button onClick={() => setShowNameModal(false)} className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl font-bold uppercase text-[10px] text-slate-600 dark:text-slate-400">Cancelar</button>
                                <button onClick={() => { setShowNameModal(false); handlePersistModel(pendingAction, modelName); }} disabled={isSavingModel || !modelName.trim()} className="flex-1 py-3 bg-indigo-600 text-white rounded-2xl font-bold uppercase text-[10px] shadow-lg shadow-indigo-500/30">
                                    {isSavingModel ? 'Salvando...' : 'Aprovar e Salvar'}
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { PhotoIcon, PlusCircleIcon, MinusIcon, ArrowPathIcon } from '../../Icons';

export const ImageRenderer: React.FC<{ file: File }> = ({ file }) => {
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [scale, setScale] = useState(1);
    const [position, setPosition] = useState({ x: 0, y: 0 });
    const [isDragging, setIsDragging] = useState(false);
    const dragStart = useRef({ x: 0, y: 0 });
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (file) {
            const url = URL.createObjectURL(file);
            setPreviewUrl(url);
            return () => URL.revokeObjectURL(url);
        }
    }, [file]);

    const handleZoomIn = () => setScale(prev => Math.min(prev + 0.25, 4));
    const handleZoomOut = () => setScale(prev => Math.max(prev - 0.25, 0.5));
    const handleReset = () => {
        setScale(1);
        setPosition({ x: 0, y: 0 });
    };

    const handleWheel = (e: React.WheelEvent) => {
        if (e.ctrlKey || e.metaKey) {
            e.preventDefault();
            if (e.deltaY < 0) handleZoomIn();
            else handleZoomOut();
        }
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        if (scale <= 1 && position.x === 0 && position.y === 0) return;
        setIsDragging(true);
        dragStart.current = { x: e.clientX - position.x, y: e.clientY - position.y };
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!isDragging) return;
        const newX = e.clientX - dragStart.current.x;
        const newY = e.clientY - dragStart.current.y;
        setPosition({ x: newX, y: newY });
    };

    const handleMouseUp = () => setIsDragging(false);

    if (!previewUrl) return null;

    return (
        <div 
            ref={containerRef}
            className="absolute inset-0 flex flex-col bg-slate-200 dark:bg-slate-950 overflow-hidden select-none"
            onWheel={handleWheel}
        >
            {/* Toolbar de Controle de Imagem */}
            <div className="absolute top-4 left-1/2 -translate-x-1/2 z-30 flex items-center gap-1 bg-white/90 dark:bg-slate-800/90 backdrop-blur-md p-1.5 rounded-2xl shadow-2xl border border-white/20">
                <button 
                    onClick={handleZoomOut}
                    className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl text-slate-600 dark:text-slate-300 transition-colors"
                    title="Diminuir Zoom"
                >
                    <MinusIcon className="w-5 h-5" />
                </button>
                <div className="px-3 min-w-[60px] text-center">
                    <span className="text-xs font-black text-slate-700 dark:text-white font-mono">
                        {Math.round(scale * 100)}%
                    </span>
                </div>
                <button 
                    onClick={handleZoomIn}
                    className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl text-slate-600 dark:text-slate-300 transition-colors"
                    title="Aumentar Zoom"
                >
                    <PlusCircleIcon className="w-5 h-5" />
                </button>
                <div className="w-px h-4 bg-slate-300 dark:bg-slate-600 mx-1"></div>
                <button 
                    onClick={handleReset}
                    className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl text-slate-600 dark:text-slate-300 transition-colors"
                    title="Resetar Visualização"
                >
                    <ArrowPathIcon className="w-5 h-5" />
                </button>
            </div>

            {/* Área da Imagem com Pan e Zoom */}
            <div 
                className={`flex-1 relative cursor-${isDragging ? 'grabbing' : scale > 1 ? 'grab' : 'default'}`}
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onMouseLeave={handleMouseUp}
            >
                <div 
                    className="absolute inset-0 flex items-center justify-center transition-transform duration-200 ease-out"
                    style={{ 
                        transform: `translate(${position.x}px, ${position.y}px) scale(${scale})`,
                        transformOrigin: 'center center'
                    }}
                >
                    <img 
                        src={previewUrl} 
                        alt="Documento Original" 
                        className="max-w-[95%] max-h-[95%] object-contain shadow-2xl pointer-events-none"
                        draggable={false}
                    />
                </div>
            </div>

            {/* Footer Informativo */}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-slate-900/60 backdrop-blur-md px-4 py-2 rounded-full border border-white/10 flex items-center gap-3 z-10 pointer-events-none opacity-80">
                <PhotoIcon className="w-4 h-4 text-amber-400" />
                <span className="text-[10px] font-bold text-white uppercase tracking-widest">
                    {scale > 1 ? 'Arraste para mover • Ctrl+Scroll para Zoom' : 'Conferência de Imagem'}
                </span>
            </div>
        </div>
    );
};

